    "0001_daily_revenue_with_7_day_moving_average_last_30_days.sql": {
      "script_id": 1,
      "mssql": "/*\n  ScriptID: 0001\n  Title: Daily revenue with 7-day moving average (last 30 days)\n  Category: report\n  Complexity: 6/10\n  Tags: SELECT, CTE, WINDOW, DATEADD\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nWITH daily AS (\n    SELECT\n        CAST(o.[OrderDate] AS DATE) AS [OrderDay],\n        SUM(o.[Total]) AS [Revenue]\n    FROM [dbo].[Orders] o\n    WHERE o.[OrderDate] >= DATEADD(day, -30, GETDATE())\n      AND o.[OrderStatus] IN ('Paid','Shipped','Delivered')\n    GROUP BY CAST(o.[OrderDate] AS DATE)\n)\nSELECT\n    [OrderDay],\n    [Revenue],\n    AVG([Revenue]) OVER (ORDER BY [OrderDay] ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS [RevenueMA7]\nFROM daily\nORDER BY [OrderDay];",
      "mysql": "/*\n  ScriptID: 0001\n  Title: Daily revenue with 7-day moving average (last 30 days)\n  Category: report\n  Complexity: 6/10\n  Tags: SELECT, CTE, WINDOW, DATEADD\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nWITH daily AS (\n    SELECT\n        CAST(o.`OrderDate` AS DATE) AS `OrderDay`,\n        SUM(o.`Total`) AS `Revenue`\n    FROM `Orders` o\n    WHERE o.`OrderDate` >= DATE_ADD(NOW(, INTERVAL -30 DAY))\n      AND o.`OrderStatus` IN ('Paid','Shipped','Delivered')\n    GROUP BY CAST(o.`OrderDate` AS DATE)\n)\nSELECT\n    `OrderDay`,\n    `Revenue`,\n    AVG(`Revenue`) OVER (ORDER BY `OrderDay` ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS `RevenueMA7`\nFROM daily\nORDER BY `OrderDay`;"
    },
    "0002_ingest_order_items_from_json_payload_openjson.sql": {
      "script_id": 2,
      "mssql": "/*\n  ScriptID: 0002\n  Title: Ingest order items from JSON payload (OPENJSON)\n  Category: etl\n  Complexity: 9/10\n  Tags: OPENJSON, JSON, ETL\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nDECLARE @orderId BIGINT = 12345;\nDECLARE @items NVARCHAR(MAX) = N'[\n    {\"ProductID\": 10, \"Quantity\": 2, \"UnitPrice\": 19.99, \"Discount\": 0},\n    {\"ProductID\": 12, \"Quantity\": 1, \"UnitPrice\": 249.00, \"Discount\": 10.00}\n]';\n\nINSERT INTO [dbo].[OrderItems]([OrderID],[ProductID],[Quantity],[UnitPrice],[Discount],[LineTotal])\nSELECT\n    @orderId,\n    j.[ProductID],\n    j.[Quantity],\n    j.[UnitPrice],\n    j.[Discount],\n    (j.[Quantity] * j.[UnitPrice]) - j.[Discount] AS [LineTotal]\nFROM OPENJSON(@items)\nWITH (\n    [ProductID] INT '$.ProductID',\n    [Quantity] INT '$.Quantity',\n    [UnitPrice] MONEY '$.UnitPrice',\n    [Discount] MONEY '$.Discount'\n) j;",
      "mysql": "/*\n  ScriptID: 0002\n  Title: Ingest order items from JSON payload (JSON_TABLE)\n  Category: etl\n  Complexity: 9/10\n  Tags: OPENJSON, JSON, ETL\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nSET @orderId := 12345;\nSET @items := JSON_ARRAY(\n    JSON_OBJECT('ProductID', 10, 'Quantity', 2, 'UnitPrice', 19.99, 'Discount', 0),\n    JSON_OBJECT('ProductID', 12, 'Quantity', 1, 'UnitPrice', 249.00, 'Discount', 10.00)\n);\n\nINSERT INTO `OrderItems`(`OrderID`,`ProductID`,`Quantity`,`UnitPrice`,`Discount`,`LineTotal`)\nSELECT\n    @orderId,\n    jt.`ProductID`,\n    jt.`Quantity`,\n    jt.`UnitPrice`,\n    jt.`Discount`,\n    (jt.`Quantity` * jt.`UnitPrice`) - jt.`Discount` AS `LineTotal`\nFROM JSON_TABLE(@items, '$[*]'\n    COLUMNS(\n        `ProductID` INT PATH '$.ProductID',\n        `Quantity` INT PATH '$.Quantity',\n        `UnitPrice` DECIMAL(19,4) PATH '$.UnitPrice',\n        `Discount` DECIMAL(19,4) PATH '$.Discount'\n    )\n) AS jt;"
    },
