    "0016_sessionize_page_views_into_visits_temp_table.sql": {
      "script_id": 16,
      "mssql": "/*\n  ScriptID: 0016\n  Title: Sessionize page views into visits (#temp table)\n  Category: analytics\n  Complexity: 7/10\n  Tags: TEMP, analytics, WINDOW\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\n-- Build a temporary session table for analysis.\nIF OBJECT_ID('tempdb..#pv') IS NOT NULL DROP TABLE #pv;\n\nSELECT\n    pv.[CustomerID],\n    pv.[ViewedAt],\n    pv.[Url],\n    DATEDIFF(minute,\n        LAG(pv.[ViewedAt]) OVER (PARTITION BY pv.[CustomerID] ORDER BY pv.[ViewedAt]),\n        pv.[ViewedAt]\n    ) AS [GapMinutes]\nINTO #pv\nFROM [dbo].[PageViews] pv\nWHERE pv.[ViewedAt] >= DATEADD(day, -7, GETDATE());\n\nSELECT\n    [CustomerID],\n    COUNT(*) AS [Views],\n    SUM(CASE WHEN [GapMinutes] IS NULL OR [GapMinutes] > 30 THEN 1 ELSE 0 END) AS [EstimatedSessions]\nFROM #pv\nGROUP BY [CustomerID]\nORDER BY [Views] DESC;",
      "mysql": "/*\n  ScriptID: 0016\n  Title: Sessionize page views into visits (TEMPORARY TABLE)\n  Category: analytics\n  Complexity: 7/10\n  Tags: TEMP, analytics, WINDOW\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nDROP TEMPORARY TABLE IF EXISTS `tmp_pv`;\n\nCREATE TEMPORARY TABLE `tmp_pv` AS\nSELECT\n    pv.`CustomerID`,\n    pv.`ViewedAt`,\n    pv.`Url`,\n    TIMESTAMPDIFF(MINUTE,\n        LAG(pv.`ViewedAt`) OVER (PARTITION BY pv.`CustomerID` ORDER BY pv.`ViewedAt`),\n        pv.`ViewedAt`\n    ) AS `GapMinutes`\nFROM `PageViews` pv\nWHERE pv.`ViewedAt` >= DATE_SUB(NOW(), INTERVAL 7 DAY);\n\nSELECT\n    `CustomerID`,\n    COUNT(*) AS `Views`,\n    SUM(CASE WHEN `GapMinutes` IS NULL OR `GapMinutes` > 30 THEN 1 ELSE 0 END) AS `EstimatedSessions`\nFROM `tmp_pv`\nGROUP BY `CustomerID`\nORDER BY `Views` DESC;"
    },
