    "0026_daily_revenue_with_7_day_moving_average_last_90_days.sql": {
      "script_id": 26,
      "mssql": "/*\n  ScriptID: 0026\n  Title: Daily revenue with 7-day moving average (last 90 days)\n  Category: report\n  Complexity: 7/10\n  Tags: SELECT, CTE, WINDOW, DATEADD\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nWITH daily AS (\n    SELECT\n        CAST(o.[OrderDate] AS DATE) AS [OrderDay],\n        SUM(o.[Total]) AS [Revenue]\n    FROM [dbo].[Orders] o\n    WHERE o.[OrderDate] >= DATEADD(day, -90, GETDATE())\n      AND o.[OrderStatus] IN ('Paid','Shipped','Delivered')\n    GROUP BY CAST(o.[OrderDate] AS DATE)\n)\nSELECT\n    [OrderDay],\n    [Revenue],\n    AVG([Revenue]) OVER (ORDER BY [OrderDay] ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS [RevenueMA7]\nFROM daily\nORDER BY [OrderDay];",
      "mysql": "/*\n  ScriptID: 0026\n  Title: Daily revenue with 7-day moving average (last 90 days)\n  Category: report\n  Complexity: 7/10\n  Tags: SELECT, CTE, WINDOW, DATEADD\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nWITH daily AS (\n    SELECT\n        CAST(o.`OrderDate` AS DATE) AS `OrderDay`,\n        SUM(o.`Total`) AS `Revenue`\n    FROM `Orders` o\n    WHERE o.`OrderDate` >= DATE_ADD(NOW(, INTERVAL -90 DAY))\n      AND o.`OrderStatus` IN ('Paid','Shipped','Delivered')\n    GROUP BY CAST(o.`OrderDate` AS DATE)\n)\nSELECT\n    `OrderDay`,\n    `Revenue`,\n    AVG(`Revenue`) OVER (ORDER BY `OrderDay` ROWS BETWEEN 6 PRECEDING AND CURRENT ROW) AS `RevenueMA7`\nFROM daily\nORDER BY `OrderDay`;"
    },
