    "0056_filter_customers_by_comma_separated_status_list_cross_apply.sql": {
      "script_id": 56,
      "mssql": "/*\n  ScriptID: 0056\n  Title: Filter customers by comma-separated status list (CROSS APPLY + STRING_SPLIT)\n  Category: query\n  Complexity: 9/10\n  Tags: CROSS APPLY, STRING_SPLIT, reporting\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nDECLARE @statuses NVARCHAR(200) = N'Active,Churned,Prospect';\n\nSELECT\n    c.[CustomerID], c.[FirstName], c.[LastName], c.[Status]\nFROM [dbo].[Customers] c\nCROSS APPLY (\n    SELECT LTRIM(RTRIM(value)) AS [StatusValue]\n    FROM STRING_SPLIT(@statuses, ',')\n) s\nWHERE c.[Status] = s.[StatusValue]\nORDER BY c.[CustomerID];",
      "mysql": "/*\n  ScriptID: 0056\n  Title: Filter customers by comma-separated status list (FIND_IN_SET)\n  Category: query\n  Complexity: 9/10\n  Tags: CROSS APPLY, STRING_SPLIT, reporting\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nSET @statuses := 'Active,Churned,Prospect';\n\nSELECT\n    c.`CustomerID`, c.`FirstName`, c.`LastName`, c.`Status`\nFROM `Customers` c\nWHERE FIND_IN_SET(c.`Status`, @statuses) > 0\nORDER BY c.`CustomerID`;\n\n-- For large lists: normalize into a table (recommended) instead of CSV parsing."
    },
