    "0059_top_customers_by_revenue_last_90_days.sql": {
      "script_id": 59,
      "mssql": "/*\n  ScriptID: 0059\n  Title: Top customers by revenue (last 90 days)\n  Category: query\n  Complexity: 5/10\n  Tags: SELECT, join, aggregate, CTE, WINDOW, TOP, DATEADD\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nWITH recent_orders AS (\n    SELECT\n        o.[OrderID],\n        o.[CustomerID],\n        o.[OrderDate],\n        o.[Total]\n    FROM [dbo].[Orders] o\n    WHERE o.[OrderDate] >= DATEADD(day, -90, GETDATE())\n      AND o.[OrderStatus] IN ('Paid','Shipped','Delivered')\n)\nSELECT TOP (100)\n    c.[CustomerID],\n    c.[FirstName],\n    c.[LastName],\n    SUM(ro.[Total]) AS [Revenue],\n    COUNT(DISTINCT ro.[OrderID]) AS [Orders],\n    ROW_NUMBER() OVER (ORDER BY SUM(ro.[Total]) DESC) AS [RankByRevenue]\nFROM recent_orders ro\nJOIN [dbo].[Customers] c ON c.[CustomerID] = ro.[CustomerID]\nGROUP BY c.[CustomerID], c.[FirstName], c.[LastName]\nORDER BY [Revenue] DESC;",
      "mysql": "/*\n  ScriptID: 0059\n  Title: Top customers by revenue (last 90 days)\n  Category: query\n  Complexity: 5/10\n  Tags: SELECT, join, aggregate, CTE, WINDOW, TOP, DATEADD\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nWITH recent_orders AS (\n    SELECT\n        o.`OrderID`,\n        o.`CustomerID`,\n        o.`OrderDate`,\n        o.`Total`\n    FROM `Orders` o\n    WHERE o.`OrderDate` >= DATE_ADD(NOW(, INTERVAL -90 DAY))\n      AND o.`OrderStatus` IN ('Paid','Shipped','Delivered')\n)\nSELECT c.`CustomerID`,\n    c.`FirstName`,\n    c.`LastName`,\n    SUM(ro.`Total`) AS `Revenue`,\n    COUNT(DISTINCT ro.`OrderID`) AS `Orders`,\n    ROW_NUMBER() OVER (ORDER BY SUM(ro.`Total`) DESC) AS `RankByRevenue`\nFROM recent_orders ro\nJOIN `Customers` c ON c.`CustomerID` = ro.`CustomerID`\nGROUP BY c.`CustomerID`, c.`FirstName`, c.`LastName`\nORDER BY `Revenue` DESC\nLIMIT 100;"
    },
