    "0076_upsert_inventory_movements_from_staging_merge.sql": {
      "script_id": 76,
      "mssql": "/*\n  ScriptID: 0076\n  Title: Upsert inventory movements from staging (MERGE)\n  Category: etl\n  Complexity: 8/10\n  Tags: MERGE, ETL, upsert\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\n-- Assume staging table [dbo].[StgInventoryMovements] is populated from files.\nMERGE [dbo].[InventoryMovements] AS tgt\nUSING (\n    SELECT [ProductID],[StoreID],[MovementType],[Quantity],[MovedAt],[Reference]\n    FROM [dbo].[StgInventoryMovements]\n) AS src\nON tgt.[ProductID] = src.[ProductID]\n   AND tgt.[StoreID] = src.[StoreID]\n   AND tgt.[MovedAt] = src.[MovedAt]\n   AND ISNULL(tgt.[Reference],'') = ISNULL(src.[Reference],'')\nWHEN MATCHED THEN\n    UPDATE SET\n        tgt.[Quantity] = src.[Quantity]\nWHEN NOT MATCHED THEN\n    INSERT ([ProductID],[StoreID],[MovementType],[Quantity],[MovedAt],[Reference])\n    VALUES (src.[ProductID],src.[StoreID],src.[MovementType],src.[Quantity],src.[MovedAt],src.[Reference]);",
      "mysql": "/*\n  ScriptID: 0076\n  Title: Upsert inventory movements from staging (ON DUPLICATE KEY UPDATE)\n  Category: etl\n  Complexity: 8/10\n  Tags: MERGE, ETL, upsert\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\n-- MySQL approach: create a UNIQUE KEY on the natural key, then use INSERT ... ON DUPLICATE KEY UPDATE.\n-- Example unique key (run once): ALTER TABLE `InventoryMovements` ADD UNIQUE KEY `UK_Inventory_Natural` (`ProductID`,`StoreID`,`MovedAt`,`Reference`);\n\nINSERT INTO `InventoryMovements`(`ProductID`,`StoreID`,`MovementType`,`Quantity`,`MovedAt`,`Reference`)\nSELECT\n    s.`ProductID`, s.`StoreID`, s.`MovementType`, s.`Quantity`, s.`MovedAt`, s.`Reference`\nFROM `StgInventoryMovements` s\nON DUPLICATE KEY UPDATE\n    `Quantity` = VALUES(`Quantity`),\n    `MovementType` = VALUES(`MovementType`);"
    },
