    "0080_ingest_order_items_from_json_payload_openjson.sql": {
      "script_id": 80,
      "mssql": "/*\n  ScriptID: 0080\n  Title: Ingest order items from JSON payload (OPENJSON)\n  Category: etl\n  Complexity: 9/10\n  Tags: OPENJSON, JSON, ETL\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nDECLARE @orderId BIGINT = 12345;\nDECLARE @items NVARCHAR(MAX) = N'[\n    {\"ProductID\": 10, \"Quantity\": 2, \"UnitPrice\": 19.99, \"Discount\": 0},\n    {\"ProductID\": 12, \"Quantity\": 1, \"UnitPrice\": 249.00, \"Discount\": 10.00}\n]';\n\nINSERT INTO [dbo].[OrderItems]([OrderID],[ProductID],[Quantity],[UnitPrice],[Discount],[LineTotal])\nSELECT\n    @orderId,\n    j.[ProductID],\n    j.[Quantity],\n    j.[UnitPrice],\n    j.[Discount],\n    (j.[Quantity] * j.[UnitPrice]) - j.[Discount] AS [LineTotal]\nFROM OPENJSON(@items)\nWITH (\n    [ProductID] INT '$.ProductID',\n    [Quantity] INT '$.Quantity',\n    [UnitPrice] MONEY '$.UnitPrice',\n    [Discount] MONEY '$.Discount'\n) j;",
      "mysql": "/*\n  ScriptID: 0080\n  Title: Ingest order items from JSON payload (JSON_TABLE)\n  Category: etl\n  Complexity: 9/10\n  Tags: OPENJSON, JSON, ETL\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nSET @orderId := 12345;\nSET @items := JSON_ARRAY(\n    JSON_OBJECT('ProductID', 10, 'Quantity', 2, 'UnitPrice', 19.99, 'Discount', 0),\n    JSON_OBJECT('ProductID', 12, 'Quantity', 1, 'UnitPrice', 249.00, 'Discount', 10.00)\n);\n\nINSERT INTO `OrderItems`(`OrderID`,`ProductID`,`Quantity`,`UnitPrice`,`Discount`,`LineTotal`)\nSELECT\n    @orderId,\n    jt.`ProductID`,\n    jt.`Quantity`,\n    jt.`UnitPrice`,\n    jt.`Discount`,\n    (jt.`Quantity` * jt.`UnitPrice`) - jt.`Discount` AS `LineTotal`\nFROM JSON_TABLE(@items, '$[*]'\n    COLUMNS(\n        `ProductID` INT PATH '$.ProductID',\n        `Quantity` INT PATH '$.Quantity',\n        `UnitPrice` DECIMAL(19,4) PATH '$.UnitPrice',\n        `Discount` DECIMAL(19,4) PATH '$.Discount'\n    )\n) AS jt;"
    },
    "0081_ingest_order_items_from_json_payload_openjson.sql": {
      "script_id": 81,
      "mssql": "/*\n  ScriptID: 0081\n  Title: Ingest order items from JSON payload (OPENJSON)\n  Category: etl\n  Complexity: 9/10\n  Tags: OPENJSON, JSON, ETL\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nDECLARE @orderId BIGINT = 12345;\nDECLARE @items NVARCHAR(MAX) = N'[\n    {\"ProductID\": 10, \"Quantity\": 2, \"UnitPrice\": 19.99, \"Discount\": 0},\n    {\"ProductID\": 12, \"Quantity\": 1, \"UnitPrice\": 249.00, \"Discount\": 10.00}\n]';\n\nINSERT INTO [dbo].[OrderItems]([OrderID],[ProductID],[Quantity],[UnitPrice],[Discount],[LineTotal])\nSELECT\n    @orderId,\n    j.[ProductID],\n    j.[Quantity],\n    j.[UnitPrice],\n    j.[Discount],\n    (j.[Quantity] * j.[UnitPrice]) - j.[Discount] AS [LineTotal]\nFROM OPENJSON(@items)\nWITH (\n    [ProductID] INT '$.ProductID',\n    [Quantity] INT '$.Quantity',\n    [UnitPrice] MONEY '$.UnitPrice',\n    [Discount] MONEY '$.Discount'\n) j;",
      "mysql": "/*\n  ScriptID: 0081\n  Title: Ingest order items from JSON payload (JSON_TABLE)\n  Category: etl\n  Complexity: 9/10\n  Tags: OPENJSON, JSON, ETL\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nSET @orderId := 12345;\nSET @items := JSON_ARRAY(\n    JSON_OBJECT('ProductID', 10, 'Quantity', 2, 'UnitPrice', 19.99, 'Discount', 0),\n    JSON_OBJECT('ProductID', 12, 'Quantity', 1, 'UnitPrice', 249.00, 'Discount', 10.00)\n);\n\nINSERT INTO `OrderItems`(`OrderID`,`ProductID`,`Quantity`,`UnitPrice`,`Discount`,`LineTotal`)\nSELECT\n    @orderId,\n    jt.`ProductID`,\n    jt.`Quantity`,\n    jt.`UnitPrice`,\n    jt.`Discount`,\n    (jt.`Quantity` * jt.`UnitPrice`) - jt.`Discount` AS `LineTotal`\nFROM JSON_TABLE(@items, '$[*]'\n    COLUMNS(\n        `ProductID` INT PATH '$.ProductID',\n        `Quantity` INT PATH '$.Quantity',\n        `UnitPrice` DECIMAL(19,4) PATH '$.UnitPrice',\n        `Discount` DECIMAL(19,4) PATH '$.Discount'\n    )\n) AS jt;"
    },
