    "0091_backfill_orderitems_linetotal_and_orders_total.sql": {
      "script_id": 91,
      "mssql": "/*\n  ScriptID: 0091\n  Title: Backfill OrderItems.LineTotal and Orders.Total\n  Category: maintenance\n  Complexity: 4/10\n  Tags: DML, maintenance, TRANSACTION\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nBEGIN TRAN;\n\nUPDATE oi\nSET oi.[LineTotal] = (oi.[Quantity] * oi.[UnitPrice]) - oi.[Discount]\nFROM [dbo].[OrderItems] oi\nWHERE oi.[LineTotal] IS NULL OR oi.[LineTotal] = 0;\n\nUPDATE o\nSET o.[Subtotal] = x.[Subtotal],\n    o.[Tax] = x.[Tax],\n    o.[Shipping] = x.[Shipping],\n    o.[Total] = x.[Total]\nFROM [dbo].[Orders] o\nJOIN (\n    SELECT\n        oi.[OrderID],\n        SUM(oi.[LineTotal]) AS [Subtotal],\n        SUM(oi.[LineTotal]) * 0.08 AS [Tax],\n        CASE WHEN SUM(oi.[LineTotal]) >= 200 THEN 0 ELSE 7.5 END AS [Shipping],\n        SUM(oi.[LineTotal]) * 1.08 + CASE WHEN SUM(oi.[LineTotal]) >= 200 THEN 0 ELSE 7.5 END AS [Total]\n    FROM [dbo].[OrderItems] oi\n    GROUP BY oi.[OrderID]\n) x ON x.[OrderID] = o.[OrderID]\nWHERE o.[OrderStatus] <> 'Cancelled';\n\nCOMMIT TRAN;",
      "mysql": "/*\n  ScriptID: 0091\n  Title: Backfill OrderItems.LineTotal and Orders.Total (MySQL rewrite)\n  Category: maintenance\n  Complexity: 4/10\n  Tags: DML, maintenance, TRANSACTION\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nSTART TRANSACTION;\n\nUPDATE `OrderItems`\nSET `LineTotal` = (`Quantity` * `UnitPrice`) - `Discount`\nWHERE `LineTotal` IS NULL OR `LineTotal` = 0;\n\nUPDATE `Orders` o\nJOIN (\n    SELECT\n        `OrderID`,\n        SUM(`LineTotal`) AS `Subtotal`,\n        SUM(`LineTotal`) * 0.08 AS `Tax`,\n        CASE WHEN SUM(`LineTotal`) >= 200 THEN 0 ELSE 7.5 END AS `Shipping`,\n        SUM(`LineTotal`) * 1.08 + CASE WHEN SUM(`LineTotal`) >= 200 THEN 0 ELSE 7.5 END AS `Total`\n    FROM `OrderItems`\n    GROUP BY `OrderID`\n) x ON x.`OrderID` = o.`OrderID`\nSET\n    o.`Subtotal` = x.`Subtotal`,\n    o.`Tax` = x.`Tax`,\n    o.`Shipping` = x.`Shipping`,\n    o.`Total` = x.`Total`\nWHERE o.`OrderStatus` <> 'Cancelled';\n\nCOMMIT;"
    },
