    "38": {
      "script_file": "0038_dynamic_sql_ad_hoc_filter_builder_sp_executesql.sql",
      "mssql": "/*\n  ScriptID: 0038\n  Title: Dynamic SQL: ad-hoc filter builder (sp_executesql)\n  Category: query\n  Complexity: 10/10\n  Tags: dynamic_sql, sp_executesql\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nDECLARE @sql NVARCHAR(MAX) = N'\n    SELECT TOP (50)\n        o.[OrderID], o.[OrderDate], o.[Total]\n    FROM [dbo].[Orders] o\n    WHERE o.[OrderDate] >= @fromDate\n      AND o.[OrderStatus] = @status\n    ORDER BY o.[OrderDate] DESC;\n';\nDECLARE @params NVARCHAR(200) = N'@fromDate DATETIME2(3), @status NVARCHAR(20)';\nEXEC sp_executesql @sql, @params, @fromDate = DATEADD(day, -30, SYSDATETIME()), @status = N''Paid'';",
      "mysql": "/*\n  ScriptID: 0038\n  Title: Dynamic SQL: ad-hoc filter builder (PREPARE)\n  Category: query\n  Complexity: 10/10\n  Tags: dynamic_sql, sp_executesql\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nSET @fromDate := DATE_SUB(NOW(3), INTERVAL 30 DAY);\nSET @status := 'Paid';\n\nSET @sql := '\n    SELECT\n        o.`OrderID`, o.`OrderDate`, o.`Total`\n    FROM `Orders` o\n    WHERE o.`OrderDate` >= ?\n      AND o.`OrderStatus` = ?\n    ORDER BY o.`OrderDate` DESC\n    LIMIT 50\n';\n\nPREPARE stmt FROM @sql;\nEXECUTE stmt USING @fromDate, @status;\nDEALLOCATE PREPARE stmt;"
    },
