      "mysql": "/*\n  ScriptID: 0062\n  Title: Store sales by category (last 7 days)\n  Category: report\n  Complexity: 6/10\n  Tags: SELECT, join, groupby, TOP, DATEADD\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nSELECT s.`StoreName`,\n    cat.`CategoryName`,\n    SUM(oi.`LineTotal`) AS `Revenue`,\n    SUM(oi.`Quantity`) AS `Units`,\n    COUNT(DISTINCT o.`OrderID`) AS `Orders`\nFROM `Orders` o\nJOIN `Stores` s ON s.`StoreID` = o.`StoreID`\nJOIN `OrderItems` oi ON oi.`OrderID` = o.`OrderID`\nJOIN `Products` p ON p.`ProductID` = oi.`ProductID`\nJOIN `Categories` cat ON cat.`CategoryID` = p.`CategoryID`\nWHERE o.`OrderDate` >= DATE_ADD(NOW(, INTERVAL -7 DAY))\n  AND o.`OrderStatus` IN ('Paid','Shipped','Delivered')\n  AND p.`IsActive` = 1\nGROUP BY s.`StoreName`, cat.`CategoryName`\nORDER BY `Revenue` DESC\nLIMIT 50;"
