    "66": {
      "script_file": "0066_stored_procedure_capture_payment_update_order_status.sql",
      "mssql": "/*\n  ScriptID: 0066\n  Title: Stored procedure: capture payment + update order status\n  Category: procedure\n  Complexity: 9/10\n  Tags: PROC, TRY/CATCH, TRANSACTION\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nCREATE OR ALTER PROCEDURE [dbo].[sp_CapturePayment]\n    @OrderID BIGINT,\n    @PaymentMethod NVARCHAR(20),\n    @Amount MONEY,\n    @AppUser NVARCHAR(80)\nAS\nBEGIN\n    SET NOCOUNT ON;\n    BEGIN TRY\n        BEGIN TRAN;\n\n        INSERT INTO [dbo].[Payments]([OrderID],[PaymentDate],[PaymentMethod],[Amount],[Status])\n        VALUES(@OrderID, SYSDATETIME(), @PaymentMethod, @Amount, N'Captured');\n\n        UPDATE [dbo].[Orders]\n        SET [OrderStatus] = N'Paid'\n        WHERE [OrderID] = @OrderID;\n\n        EXEC sys.sp_set_session_context @key = N'app_user', @value = @AppUser;\n\n        COMMIT TRAN;\n    END TRY\n    BEGIN CATCH\n        IF @@TRANCOUNT > 0 ROLLBACK TRAN;\n        DECLARE @msg NVARCHAR(4000) = ERROR_MESSAGE();\n        RAISERROR(@msg, 16, 1);\n    END CATCH\nEND\nGO",
      "mysql": "/*\n  ScriptID: 0066\n  Title: Stored procedure: capture payment + update order status (handlers)\n  Category: procedure\n  Complexity: 9/10\n  Tags: PROC, TRY/CATCH, TRANSACTION\n  GeneratedFor: MSSQL -> MySQL migration demo (LLM + coding agents)\n*/\n\nDELIMITER $$\n\nCREATE PROCEDURE `sp_CapturePayment`(\n    IN p_OrderID BIGINT,\n    IN p_PaymentMethod VARCHAR(20),\n    IN p_Amount DECIMAL(19,4),\n    IN p_AppUser VARCHAR(80)\n)\nBEGIN\n    DECLARE exit handler for sqlexception\n    BEGIN\n        ROLLBACK;\n        RESIGNAL;\n    END;\n\n    START TRANSACTION;\n\n    SET @app_user := p_AppUser;\n\n    INSERT INTO `Payments`(`OrderID`,`PaymentDate`,`PaymentMethod`,`Amount`,`Status`)\n    VALUES(p_OrderID, NOW(3), p_PaymentMethod, p_Amount, 'Captured');\n\n    UPDATE `Orders`\n    SET `OrderStatus` = 'Paid'\n    WHERE `OrderID` = p_OrderID;\n\n    COMMIT;\nEND$$\n\nDELIMITER ;"
    },
